import pymongo

def find_users_by_email(email):
    client = pymongo.MongoClient("mongodb://localhost:27017/")
    db = client["mydatabase"]
    users = db["users"]

    # Use the $regex operator to match email addresses
    query = {"email": {"$regex": f"^{email}$", "$options": "i"}}

    # Use the find() method to retrieve the matching documents
    results = users.find(query)

    # Close the client connection
    client.close()

    return list(results)